import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { PawPrint, LogOut } from 'lucide-react';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  return (
    <nav className="flex justify-between items-center p-5 bg-white shadow-sm sticky top-0 z-[1000]">
      <Link to="/" className="text-2xl font-bold text-green-600 flex items-center gap-2"><PawPrint /> FoodBridge</Link>
      <div className="flex gap-6 items-center">
        <Link to="/">Home</Link>
        {user ? (
          <>
            <Link to={user.role === 'reporter' ? '/report-home' : '/dashboard'}>Portal</Link>
            <button onClick={() => { logout(); navigate('/'); }} className="text-red-500 flex items-center gap-1"><LogOut size={18}/> Logout</button>
          </>
        ) : ( <Link to="/login" className="bg-green-600 text-white px-5 py-2 rounded-full">Login</Link> )}
      </div>
    </nav>
  );
}
